export const ERROR_NON_ADJACENT = "Cannot connect non-adjacent islands";
export const ERROR_MAX_2 = "Max 2 bridges per pair";
export const ERROR_EXCEED = "Island would exceed its number";
export const ERROR_CROSS = "Bridges would cross";

export function canonicalBridgeKey(from, to) {
  // from/to are {x,y} in grid units
  const a = { x: from.x, y: from.y };
  const b = { x: to.x, y: to.y };
  const swap = a.x > b.x || (a.x === b.x && a.y > b.y);
  const p = swap ? b : a;
  const q = swap ? a : b;
  return `${p.x},${p.y},${q.x},${q.y}`;
}

function parseKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }

  return counts;
}

function isCardinalAdjacent(islands, from, to) {
  if (from.id === to.id) return { ok: false, reason: 'same' };
  if (from.x !== to.x && from.y !== to.y) return { ok: false, reason: 'not_cardinal' };

  if (from.x === to.x) {
    const x = from.x;
    const minY = Math.min(from.y, to.y);
    const maxY = Math.max(from.y, to.y);
    // any island strictly between blocks adjacency
    const between = islands.some((i) => i.x === x && i.y > minY && i.y < maxY);
    return { ok: !between, reason: between ? 'blocked' : null };
  }

  const y = from.y;
  const minX = Math.min(from.x, to.x);
  const maxX = Math.max(from.x, to.x);
  const between = islands.some((i) => i.y === y && i.x > minX && i.x < maxX);
  return { ok: !between, reason: between ? 'blocked' : null };
}

function bridgeSegmentsFromKey(key) {
  const { x1, y1, x2, y2 } = parseKey(key);
  const horiz = y1 === y2;
  const vert = x1 === x2;
  if (!horiz && !vert) return null;
  if (horiz) {
    const y = y1;
    const minX = Math.min(x1, x2);
    const maxX = Math.max(x1, x2);
    return { type: 'h', y, x1: minX, x2: maxX };
  }
  const x = x1;
  const minY = Math.min(y1, y2);
  const maxY = Math.max(y1, y2);
  return { type: 'v', x, y1: minY, y2: maxY };
}

function segmentsCross(segA, segB) {
  // Bridges that share an endpoint (i.e. touch at an island) are OK.
  if (!segA || !segB) return false;
  if (segA.type === segB.type) return false; // parallel won't cross in Hashi model

  const h = segA.type === 'h' ? segA : segB;
  const v = segA.type === 'v' ? segA : segB;

  // intersection point
  const ix = v.x;
  const iy = h.y;

  const withinH = ix > h.x1 && ix < h.x2;
  const withinV = iy > v.y1 && iy < v.y2;
  return withinH && withinV;
}

function wouldCrossExisting(bridges, newKey) {
  const newSeg = bridgeSegmentsFromKey(newKey);
  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    if (key === newKey) continue;
    const seg = bridgeSegmentsFromKey(key);
    if (segmentsCross(newSeg, seg)) return true;
  }
  return false;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  // delta: +1, +2, -1, -2, or special removal handled by caller.
  const adj = isCardinalAdjacent(islands, from, to);
  if (!adj.ok) return { valid: false, error: ERROR_NON_ADJACENT };

  const key = canonicalBridgeKey(from, to);
  const existing = bridges.get(key) ?? 0;
  const next = existing + delta;

  if (next < 0) return { valid: true, error: null };
  if (next > 2) return { valid: false, error: ERROR_MAX_2 };

  // crossing check only if we are adding (increasing)
  if (delta > 0) {
    const temp = new Map(bridges);
    temp.set(key, next);
    if (wouldCrossExisting(bridges, key)) return { valid: false, error: ERROR_CROSS };
    // also ensure adding this does not cross any existing (already checked)
    // and existing does not cross with the new one (symmetric)
    // counts check
    const counts = computeCurrentCounts(islands, temp);
    for (const isl of islands) {
      if ((counts.get(isl.id) ?? 0) > isl.value) return { valid: false, error: ERROR_EXCEED };
    }
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length <= 1) return true;

  // Build adjacency by island id.
  const byCoord = new Map(islands.map((i) => [`${i.x},${i.y}`, i]));
  const adj = new Map(islands.map((i) => [i.id, []]));

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = byCoord.get(`${x1},${y1}`);
    const b = byCoord.get(`${x2},${y2}`);
    if (!a || !b) continue;
    adj.get(a.id).push(b.id);
    adj.get(b.id).push(a.id);
  }

  const startId = islands[0].id;
  const seen = new Set([startId]);
  const queue = [startId];
  while (queue.length) {
    const cur = queue.shift();
    for (const nxt of adj.get(cur) || []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        queue.push(nxt);
      }
    }
  }

  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  // no crossings
  for (const [k1, n1] of bridges.entries()) {
    if (!n1) continue;
    const s1 = bridgeSegmentsFromKey(k1);
    for (const [k2, n2] of bridges.entries()) {
      if (!n2) continue;
      if (k1 === k2) continue;
      const s2 = bridgeSegmentsFromKey(k2);
      if (segmentsCross(s1, s2)) return false;
    }
  }

  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }

  return checkConnectivity(islands, bridges);
}
EOF

cat > /app/src/App.jsx <<'EOF'
import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canAddBridge,
  canonicalBridgeKey,
  computeCurrentCounts,
  isVictory,
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function islandKey(i) {
  return `${i.x},${i.y}`;
}

function getIslandById(islands, id) {
  return islands.find((i) => i.id === id) ?? null;
}

function getIslandAt(islands, x, y) {
  return islands.find((i) => i.x === x && i.y === y) ?? null;
}

function neighborsInDirection(islands, from, dir) {
  // returns closest island in that direction if any
  if (!from) return null;
  if (dir === 'left') {
    const cands = islands.filter((i) => i.y === from.y && i.x < from.x);
    if (!cands.length) return null;
    return cands.reduce((a, b) => (b.x > a.x ? b : a));
  }
  if (dir === 'right') {
    const cands = islands.filter((i) => i.y === from.y && i.x > from.x);
    if (!cands.length) return null;
    return cands.reduce((a, b) => (b.x < a.x ? b : a));
  }
  if (dir === 'up') {
    const cands = islands.filter((i) => i.x === from.x && i.y < from.y);
    if (!cands.length) return null;
    return cands.reduce((a, b) => (b.y > a.y ? b : a));
  }
  if (dir === 'down') {
    const cands = islands.filter((i) => i.x === from.x && i.y > from.y);
    if (!cands.length) return null;
    return cands.reduce((a, b) => (b.y < a.y ? b : a));
  }
  return null;
}

function bridgeLinesFor(key, count) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  const px1 = x1 * GRID;
  const py1 = y1 * GRID;
  const px2 = x2 * GRID;
  const py2 = y2 * GRID;

  const isH = py1 === py2;
  const isV = px1 === px2;

  const lines = [];
  if (count === 1) {
    lines.push({ x1: px1, y1: py1, x2: px2, y2: py2 });
  } else if (count === 2) {
    const off = 6;
    if (isH) {
      lines.push({ x1: px1, y1: py1 - off, x2: px2, y2: py2 - off });
      lines.push({ x1: px1, y1: py1 + off, x2: px2, y2: py2 + off });
    } else if (isV) {
      lines.push({ x1: px1 - off, y1: py1, x2: px2 - off, y2: py2 });
      lines.push({ x1: px1 + off, y1: py1, x2: px2 + off, y2: py2 });
    }
  }
  return lines;
}

export default function App() {
  const [difficulty, setDifficulty] = useState('Easy');
  const puzzle = useMemo(() => puzzles.find((p) => p.name === difficulty) ?? puzzles[0], [difficulty]);
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedIslandId, setSelectedIslandId] = useState(null); // mouse selection

  const [cursorIslandId, setCursorIslandId] = useState(islands[0]?.id ?? 0);
  const [kbFromId, setKbFromId] = useState(null);

  const [error, setError] = useState(null);

  const svgRef = useRef(null);

  // reset when puzzle changes
  useEffect(() => {
    setBridges(new Map());
    setSelectedIslandId(null);
    setKbFromId(null);
    setError(null);
    setCursorIslandId(islands[0]?.id ?? 0);
  }, [puzzle.id]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function applyValidUpdate(nextBridges) {
    setBridges(nextBridges);
    setError(null);
  }

  function toggleBridge(from, to) {
    const key = canonicalBridgeKey(from, to);
    const existing = bridges.get(key) ?? 0;
    const next = (existing + 1) % 3; // 0->1->2->0

    const nextMap = new Map(bridges);

    if (next === 0) {
      nextMap.delete(key);
      applyValidUpdate(nextMap);
      return;
    }

    const delta = next - existing;
    const res = canAddBridge(islands, bridges, from, to, delta);
    if (!res.valid) {
      setError(res.error);
      return;
    }
    nextMap.set(key, next);
    applyValidUpdate(nextMap);
  }

  function removeBridgeIfExists(from, to) {
    const key = canonicalBridgeKey(from, to);
    const existing = bridges.get(key) ?? 0;
    if (!existing) {
      setError(null);
      return;
    }
    const nextMap = new Map(bridges);
    nextMap.delete(key);
    applyValidUpdate(nextMap);
  }

  function handleIslandClick(e, isl) {
    // ctrl+click removes bridge if second endpoint selected
    if (e.ctrlKey) {
      if (selectedIslandId !== null && selectedIslandId !== isl.id) {
        const from = getIslandById(islands, selectedIslandId);
        removeBridgeIfExists(from, isl);
        setSelectedIslandId(null);
      } else {
        setSelectedIslandId(isl.id);
      }
      return;
    }

    if (selectedIslandId === null) {
      setSelectedIslandId(isl.id);
      setError(null);
      return;
    }

    if (selectedIslandId === isl.id) {
      // keep selection
      return;
    }

    const from = getIslandById(islands, selectedIslandId);
    toggleBridge(from, isl);
    setSelectedIslandId(null);
  }

  function handleIslandContextMenu(e, isl) {
    e.preventDefault();
    if (selectedIslandId !== null && selectedIslandId !== isl.id) {
      const from = getIslandById(islands, selectedIslandId);
      removeBridgeIfExists(from, isl);
      setSelectedIslandId(null);
    } else {
      // if no first selection, just select this island as start for convenience
      setSelectedIslandId(isl.id);
    }
  }

  useEffect(() => {
    function onKeyDown(e) {
      const active = document.activeElement;
      if (active && (active.tagName === 'SELECT' || active.tagName === 'BUTTON')) return;

      const cur = getIslandById(islands, cursorIslandId) ?? islands[0];
      if (!cur) return;

      const dir =
        e.key === 'ArrowLeft'
          ? 'left'
          : e.key === 'ArrowRight'
            ? 'right'
            : e.key === 'ArrowUp'
              ? 'up'
              : e.key === 'ArrowDown'
                ? 'down'
                : null;

      if (dir) {
        e.preventDefault();
        const nxt = neighborsInDirection(islands, cur, dir);
        if (nxt) setCursorIslandId(nxt.id);
        return;
      }

      if (e.key === 'Escape') {
        setKbFromId(null);
        setError(null);
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        if (kbFromId === null) {
          setKbFromId(cursorIslandId);
          setError(null);
          return;
        }
        if (kbFromId === cursorIslandId) return;
        const from = getIslandById(islands, kbFromId);
        const to = getIslandById(islands, cursorIslandId);
        toggleBridge(from, to);
        setKbFromId(null);
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [islands, cursorIslandId, kbFromId, bridges]);

  const bridgeLineElements = [];
  for (const [key, count] of bridges.entries()) {
    const lines = bridgeLinesFor(key, count);
    lines.forEach((ln, idx) => {
      bridgeLineElements.push(
        <line
          key={`${key}:${idx}`}
          x1={ln.x1}
          y1={ln.y1}
          x2={ln.x2}
          y2={ln.y2}
          stroke="#0f0"
          strokeWidth={3}
          shapeRendering="crispEdges"
        />
      );
    });
  }

  const cursorIsl = getIslandById(islands, cursorIslandId);
  const cursorPx = cursorIsl ? { x: cursorIsl.x * GRID, y: cursorIsl.y * GRID } : { x: 0, y: 0 };

  return (
    <div className="app-root">
      <div className="ui-bar">
        <label>
          Puzzle:{' '}
          <select
            value={difficulty}
            onChange={(e) => setDifficulty(e.target.value)}
            aria-label="Puzzle difficulty"
          >
            <option value="Easy">Easy</option>
            <option value="Medium">Medium</option>
            <option value="Hard">Hard</option>
          </select>
        </label>
        <button
          type="button"
          onClick={() => {
            setBridges(new Map());
            setSelectedIslandId(null);
            setKbFromId(null);
            setError(null);
          }}
        >
          Reset
        </button>
        <div className="counts-hint">
          Selected: {selectedIslandId !== null ? selectedIslandId : '-'} | Cursor: {cursorIslandId}
        </div>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        ref={svgRef}
        width={SVG_W}
        height={SVG_H}
        className="board-svg"
        style={{ display: 'block' }}
      >
        {/* bridges under islands */}
        {bridgeLineElements}

        {/* keyboard cursor (not a circle) */}
        {cursorIsl ? (
          <rect
            x={cursorPx.x - 18}
            y={cursorPx.y - 18}
            width={36}
            height={36}
            fill="none"
            stroke={kbFromId !== null ? '#9f9' : '#0f0'}
            strokeWidth={2}
            strokeDasharray={kbFromId !== null ? '4 3' : '0'}
          />
        ) : null}

        {/* islands */}
        {islands.map((isl) => {
          const px = isl.x * GRID;
          const py = isl.y * GRID;
          const isSelected = selectedIslandId === isl.id || kbFromId === isl.id;
          const current = counts.get(isl.id) ?? 0;

          return (
            <g key={isl.id}>
              <circle
                cx={px}
                cy={py}
                r={16}
                fill="black"
                stroke={isSelected ? '#9f9' : '#0f0'}
                strokeWidth={2}
                onClick={(e) => handleIslandClick(e, isl)}
                onContextMenu={(e) => handleIslandContextMenu(e, isl)}
              />
              <text
                x={px}
                y={py + 5}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={16}
                fill="#0f0"
                style={{ userSelect: 'none', pointerEvents: 'none' }}
              >
                {isl.value}
              </text>
              <text
                x={px}
                y={py + 28}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={10}
                fill="#0f0"
                style={{ userSelect: 'none', pointerEvents: 'none' }}
              >
                {current}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
EOF

