import React, { useEffect, useMemo, useState } from 'react';
import { puzzles } from './data/puzzles';
import {
  canAddBridge,
  canonicalBridgeKey,
  computeCurrentCounts,
  isVictory,
} from './utils/hashiLogic';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function getIslandById(islands, id) {
  return islands.find((i) => i.id === id) ?? null;
}

function neighborsInDirection(islands, from, dir) {
  if (!from) return null;
  if (dir === 'left') {
    const cands = islands.filter((i) => i.y === from.y && i.x < from.x);
    if (!cands.length) return null;
    return cands.reduce((a, b) => (b.x > a.x ? b : a));
  }
  if (dir === 'right') {
    const cands = islands.filter((i) => i.y === from.y && i.x > from.x);
    if (!cands.length) return null;
    return cands.reduce((a, b) => (b.x < a.x ? b : a));
  }
  if (dir === 'up') {
    const cands = islands.filter((i) => i.x === from.x && i.y < from.y);
    if (!cands.length) return null;
    return cands.reduce((a, b) => (b.y > a.y ? b : a));
  }
  if (dir === 'down') {
    const cands = islands.filter((i) => i.x === from.x && i.y > from.y);
    if (!cands.length) return null;
    return cands.reduce((a, b) => (b.y < a.y ? b : a));
  }
  return null;
}

function bridgeLinesFor(key, count) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  const px1 = x1 * GRID;
  const py1 = y1 * GRID;
  const px2 = x2 * GRID;
  const py2 = y2 * GRID;

  const isH = py1 === py2;
  const isV = px1 === px2;

  const lines = [];
  if (count === 1) {
    lines.push({ x1: px1, y1: py1, x2: px2, y2: py2 });
  } else if (count === 2) {
    const off = 6;
    if (isH) {
      lines.push({ x1: px1, y1: py1 - off, x2: px2, y2: py2 - off });
      lines.push({ x1: px1, y1: py1 + off, x2: px2, y2: py2 + off });
    } else if (isV) {
      lines.push({ x1: px1 - off, y1: py1, x2: px2 - off, y2: py2 });
      lines.push({ x1: px1 + off, y1: py1, x2: px2 + off, y2: py2 });
    }
  }
  return lines;
}

export default function App() {
  const [difficulty, setDifficulty] = useState('Easy');
  const puzzle = useMemo(() => puzzles.find((p) => p.name === difficulty) ?? puzzles[0], [difficulty]);
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedIslandId, setSelectedIslandId] = useState(null); // mouse selection

  const [cursorIslandId, setCursorIslandId] = useState(islands[0]?.id ?? 0);
  const [kbFromId, setKbFromId] = useState(null);

  const [error, setError] = useState(null);

  useEffect(() => {
    setBridges(new Map());
    setSelectedIslandId(null);
    setKbFromId(null);
    setError(null);
    setCursorIslandId(islands[0]?.id ?? 0);
  }, [puzzle.id]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function applyValidUpdate(nextBridges) {
    setBridges(nextBridges);
    setError(null);
  }

  function toggleBridge(from, to) {
    const key = canonicalBridgeKey(from, to);
    const existing = bridges.get(key) ?? 0;
    const next = (existing + 1) % 3; // 0->1->2->0

    const nextMap = new Map(bridges);

    if (next === 0) {
      nextMap.delete(key);
      applyValidUpdate(nextMap);
      return;
    }

    const delta = next - existing;
    const res = canAddBridge(islands, bridges, from, to, delta);
    if (!res.valid) {
      setError(res.error);
      return;
    }
    nextMap.set(key, next);
    applyValidUpdate(nextMap);
  }

  function removeBridgeByKey(key) {
    if (!(bridges.get(key) > 0)) {
      setError(null);
      return;
    }
    const nextMap = new Map(bridges);
    nextMap.delete(key);
    applyValidUpdate(nextMap);
  }

  function handleIslandClick(e, isl) {
    if (e.ctrlKey) {
      // ctrl+click should remove an existing bridge if there's an active selection to pair with
      if (selectedIslandId !== null && selectedIslandId !== isl.id) {
        const from = getIslandById(islands, selectedIslandId);
        const key = canonicalBridgeKey(from, isl);
        removeBridgeByKey(key);
        setSelectedIslandId(null);
      } else {
        setSelectedIslandId(isl.id);
      }
      return;
    }

    if (selectedIslandId === null) {
      setSelectedIslandId(isl.id);
      setError(null);
      return;
    }

    if (selectedIslandId === isl.id) return;

    const from = getIslandById(islands, selectedIslandId);
    toggleBridge(from, isl);
    setSelectedIslandId(null);
  }

  function handleIslandContextMenu(e, isl) {
    e.preventDefault();
    if (selectedIslandId !== null && selectedIslandId !== isl.id) {
      const from = getIslandById(islands, selectedIslandId);
      const key = canonicalBridgeKey(from, isl);
      removeBridgeByKey(key);
      setSelectedIslandId(null);
    } else {
      setSelectedIslandId(isl.id);
    }
  }

  useEffect(() => {
    function onKeyDown(e) {
      const active = document.activeElement;
      if (active && (active.tagName === 'SELECT' || active.tagName === 'BUTTON')) return;

      const cur = getIslandById(islands, cursorIslandId) ?? islands[0];
      if (!cur) return;

      const dir =
        e.key === 'ArrowLeft'
          ? 'left'
          : e.key === 'ArrowRight'
            ? 'right'
            : e.key === 'ArrowUp'
              ? 'up'
              : e.key === 'ArrowDown'
                ? 'down'
                : null;

      if (dir) {
        e.preventDefault();
        const nxt = neighborsInDirection(islands, cur, dir);
        if (nxt) setCursorIslandId(nxt.id);
        return;
      }

      if (e.key === 'Escape') {
        setKbFromId(null);
        setError(null);
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        if (kbFromId === null) {
          setKbFromId(cursorIslandId);
          setError(null);
          return;
        }
        if (kbFromId === cursorIslandId) return;
        const from = getIslandById(islands, kbFromId);
        const to = getIslandById(islands, cursorIslandId);
        toggleBridge(from, to);
        setKbFromId(null);
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [islands, cursorIslandId, kbFromId, bridges]);

  const cursorIsl = getIslandById(islands, cursorIslandId);
  const cursorPx = cursorIsl ? { x: cursorIsl.x * GRID, y: cursorIsl.y * GRID } : { x: 0, y: 0 };

  const bridgeLineElements = [];
  for (const [key, count] of bridges.entries()) {
    const lines = bridgeLinesFor(key, count);
    lines.forEach((ln, idx) => {
      bridgeLineElements.push(
        <line
          key={`${key}:${idx}`}
          x1={ln.x1}
          y1={ln.y1}
          x2={ln.x2}
          y2={ln.y2}
          stroke="#0f0"
          strokeWidth={3}
          shapeRendering="crispEdges"
          onContextMenu={(e) => {
            e.preventDefault();
            removeBridgeByKey(key);
          }}
          onClick={(e) => {
            if (e.ctrlKey) removeBridgeByKey(key);
          }}
        />
      );
    });
  }

  return (
    <div className="app-root">
      {/* board SVG anchored to viewport top-left */}
      <svg width={SVG_W} height={SVG_H} className="board-svg" style={{ display: 'block' }}>
        {bridgeLineElements}

        {/* keyboard cursor (not a circle) */}
        {cursorIsl ? (
          <rect
            x={cursorPx.x - 18}
            y={cursorPx.y - 18}
            width={36}
            height={36}
            fill="none"
            stroke={kbFromId !== null ? '#9f9' : '#0f0'}
            strokeWidth={2}
            strokeDasharray={kbFromId !== null ? '4 3' : '0'}
          />
        ) : null}

        {islands.map((isl) => {
          const px = isl.x * GRID;
          const py = isl.y * GRID;
          const isSelected = selectedIslandId === isl.id || kbFromId === isl.id;
          const current = counts.get(isl.id) ?? 0;

          return (
            <g key={isl.id}>
              <circle
                cx={px}
                cy={py}
                r={16}
                fill="black"
                stroke={isSelected ? '#9f9' : '#0f0'}
                strokeWidth={2}
                onClick={(e) => handleIslandClick(e, isl)}
                onContextMenu={(e) => handleIslandContextMenu(e, isl)}
              />
              <text
                x={px}
                y={py + 5}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={16}
                fill="#0f0"
                style={{ userSelect: 'none', pointerEvents: 'none' }}
              >
                {isl.value}
              </text>
              <text
                x={px}
                y={py + 28}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={10}
                fill="#0f0"
                style={{ userSelect: 'none', pointerEvents: 'none' }}
              >
                {current}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>

      {/* UI overlay that does not move the SVG from (0,0) */}
      <div className="ui-overlay">
        <div className="ui-bar">
          <label>
            Puzzle:{' '}
            <select value={difficulty} onChange={(e) => setDifficulty(e.target.value)} aria-label="Puzzle difficulty">
              <option value="Easy">Easy</option>
              <option value="Medium">Medium</option>
              <option value="Hard">Hard</option>
            </select>
          </label>
          <button
            type="button"
            onClick={() => {
              setBridges(new Map());
              setSelectedIslandId(null);
              setKbFromId(null);
              setError(null);
            }}
          >
            Reset
          </button>
        </div>

        {error ? <div className="error-message">{error}</div> : null}
        {victory ? <div className="victory-banner">SOLVED!</div> : null}
      </div>
    </div>
  );
}
